package pages;import org.openqa.selenium.By;import org.openqa.selenium.WebDriver;import org.openqa.selenium.support.ui.Select;public class AdminPage {    private WebDriver driver;    public AdminPage(WebDriver driver) {        this.driver = driver;    }    public boolean panelAdministradorVisible() {        return driver.getPageSource().contains("Panel Administrador");    }    public void seleccionarEstadoTodos() {        Select estado = new Select(driver.findElement(By.name("status")));        estado.selectByValue("");    }    public void filtrar() {        driver.findElement(By.cssSelector("button.filter-submit")).click();    }    public boolean tablaPedidosVisible() {        return driver.getPageSource().contains("ID_Mozo")                && driver.getPageSource().contains("Estado_pedido")                && driver.getPageSource().contains("Ver detalle");    }    public boolean estadisticasVisibles() {        return driver.getPageSource().contains("Estadísticas")                && driver.getPageSource().contains("Total Pedidos Completados")                && driver.getPageSource().contains("Total Ganancias");    }    public void seleccionarEstado(String estadoValue) {        Select estado = new Select(driver.findElement(By.name("status")));        estado.selectByValue(estadoValue);    }    public void seleccionarMes(String mesValue) {        Select mes = new Select(driver.findElement(By.name("month")));        mes.selectByValue(mesValue);    }    public boolean estadoEnTablaVisible(String estado) {        return driver.getPageSource().contains(estado);    }}